from pathlib import Path
import csv
import json


# Repository root:
# video-perception-pipeline/
REPO_ROOT = Path(__file__).resolve().parents[1]

# Human-reviewed labels created manually after inspecting sampled frames
MANUAL_LABELS_CSV = (
    REPO_ROOT / "data" / "evaluation" / "manual_labels.csv"
)

# Prediction export generated by the prediction export pipeline
PREDICTIONS_JSONL = REPO_ROOT / "outputs" / "predictions.jsonl"

# Output folder for evaluation helper files
EVALUATION_DIR = REPO_ROOT / "outputs" / "evaluation"

# Side-by-side file used to inspect manual labels against model predictions
REVIEW_COMPARISON_CSV = EVALUATION_DIR / "manual_vs_predictions.csv"


def load_manual_labels():
    """
    Load the human-reviewed evaluation subset.

    This file is manually created by inspecting sampled frames.
    """

    if not MANUAL_LABELS_CSV.exists():
        raise FileNotFoundError(
            f"Manual labels not found: {MANUAL_LABELS_CSV}"
        )

    rows = []

    with open(MANUAL_LABELS_CSV, "r", encoding="utf-8") as f:
        reader = csv.DictReader(f)

        for row in reader:
            rows.append({
                "video_id": row["video_id"],
                "frame_name": row["frame_name"],
                "frame_index": int(row["frame_index"]),
                "class_label": row["class_label"],
                "present": int(row["present"]),
                "box_optional": row["box_optional"],
                "notes": row["notes"],
            })

    return rows


def load_predictions():
    """
    Load exported predictions.

    The prediction export contains model detections with:
    - video ID
    - original frame index
    - class label
    - bounding box
    - track ID
    - confidence
    """

    if not PREDICTIONS_JSONL.exists():
        raise FileNotFoundError(
            f"Predictions not found: {PREDICTIONS_JSONL}. "
            "Run: python3 src/export_predictions_jsonl.py"
        )

    predictions = []

    with open(PREDICTIONS_JSONL, "r", encoding="utf-8") as f:
        for line in f:
            predictions.append(json.loads(line))

    return predictions


def find_predictions_for_label(label, predictions):
    """
    Find model predictions that match one manually reviewed frame.

    This is a simple review helper.
    Full precision/recall metrics will be computed in the evaluation step.
    """

    matches = []

    for prediction in predictions:
        same_video = prediction["video_id"] == label["video_id"]
        same_frame = prediction["frame_index"] == label["frame_index"]

        if same_video and same_frame:
            matches.append(prediction)

    return matches


def save_review_comparison(manual_labels, predictions):
    """
    Save a side-by-side comparison file.

    This helps inspect:
    - frames where the object was manually marked present
    - frames where the model produced detections
    - obvious misses and false positives
    """

    EVALUATION_DIR.mkdir(parents=True, exist_ok=True)

    with open(
        REVIEW_COMPARISON_CSV,
        "w",
        newline="",
        encoding="utf-8",
    ) as f:

        fieldnames = [
            "video_id",
            "frame_name",
            "frame_index",
            "manual_class_label",
            "manual_present",
            "manual_notes",
            "num_predictions_on_frame",
            "predicted_classes",
            "prediction_confidences",
            "prediction_track_ids",
        ]

        writer = csv.DictWriter(f, fieldnames=fieldnames)
        writer.writeheader()

        for label in manual_labels:
            frame_predictions = find_predictions_for_label(
                label=label,
                predictions=predictions,
            )

            predicted_classes = [
                prediction["class_label"]
                for prediction in frame_predictions
            ]

            prediction_confidences = [
                str(round(prediction["confidence"], 3))
                for prediction in frame_predictions
            ]

            prediction_track_ids = [
                str(prediction["track_id"])
                for prediction in frame_predictions
            ]

            writer.writerow({
                "video_id": label["video_id"],
                "frame_name": label["frame_name"],
                "frame_index": label["frame_index"],
                "manual_class_label": label["class_label"],
                "manual_present": label["present"],
                "manual_notes": label["notes"],
                "num_predictions_on_frame": len(frame_predictions),
                "predicted_classes": ";".join(predicted_classes),
                "prediction_confidences": ";".join(prediction_confidences),
                "prediction_track_ids": ";".join(prediction_track_ids),
            })


def main():
    """
    Manual evaluation subset preparation.

    1. Load human-reviewed labels.
    2. Load exported model predictions.
    3. Match manual frames with predictions.
    4. Save a side-by-side CSV for inspection.
    """

    manual_labels = load_manual_labels()
    predictions = load_predictions()

    save_review_comparison(
        manual_labels=manual_labels,
        predictions=predictions,
    )

    print(f"Loaded manual labels: {len(manual_labels)}")
    print(f"Loaded predictions: {len(predictions)}")
    print(f"Review comparison saved to: {REVIEW_COMPARISON_CSV}")


if __name__ == "__main__":
    main()
